// n8n-marcin/15-bip-przetargi.json — Fetch BIP Przetargi
// Purpose: Query BIP e-bip.eu AJAX API for recent przetargi, check Qdrant for new ones
// NOT for: generating content

const qdrantUrl = 'http://qdrant:6333';
const bipUrl = 'https://powiatkrasnik.e-bip.eu/index.php?id=724&ajax=pobierz_przetargi';

// Step 1: Get total count with minimal data
let total = 0;
let rows = [];
try {
  // First get just 1 row to learn total count
  const countData = await this.helpers.httpRequest({
    method: 'GET',
    url: bipUrl + '&sEcho=1&iDisplayStart=0&iDisplayLength=1',
    json: true
  });
  total = countData.iTotalRecords || 0;

  // Then fetch only the last 30 rows (most recent)
  const startFrom = Math.max(0, total - 30);
  const bipData = await this.helpers.httpRequest({
    method: 'GET',
    url: bipUrl + '&sEcho=2&iDisplayStart=' + startFrom + '&iDisplayLength=30',
    json: true
  });
  rows = bipData.aaData || [];
} catch (e) {
  console.log('BIP fetch error:', e.message);
  // Return empty so workflow doesn't crash
  return [{ json: { newPrzetargi: [], totalInBIP: 0, checkedCount: 0, error: e.message } }];
}

// Parse rows: Col 1=ID, 4=date, 6=title, 8=deadline
const przetargi = rows.map(row => {
  const id = String(row[1]);
  const date = String(row[4] || '');
  const title = String(row[6] || '').replace(/<[^>]+>/g, '').trim();
  const deadline = String(row[8] || '');
  const bipLink = 'https://powiatkrasnik.e-bip.eu/index.php?id=' + id;
  return { id, date, title, deadline, bipLink };
}).filter(p => p.title.length > 10);

// Check Qdrant for already-notified przetargi
const notifiedResult = await this.helpers.httpRequest({
  method: 'POST',
  url: qdrantUrl + '/collections/krasnik_news/points/scroll',
  body: {
    limit: 200,
    with_payload: true,
    with_vector: false,
    filter: { must: [{ key: 'category', match: { value: 'bip-przetarg-notified' } }] }
  },
  json: true
}).catch(e => ({ result: { points: [] } }));

const notifiedIds = new Set(
  (notifiedResult.result?.points || []).map(p => p.payload?.bip_id || '')
);

// Filter new przetargi
const newPrzetargi = przetargi.filter(p => !notifiedIds.has(p.id));

// Only keep przetargi from last 30 days
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 30);
const cutoffStr = cutoff.toISOString().slice(0, 10);

const freshNew = newPrzetargi.filter(p => p.date >= cutoffStr);

return [{ json: { newPrzetargi: freshNew, totalInBIP: total, checkedCount: przetargi.length } }];

const GROUP_JID = $env.WHATSAPP_GROUP_JID || '120363426348074659@g.us';
// n8n-marcin/15-bip-przetargi.json — Format & Store
// Purpose: Format WhatsApp message + store notified IDs in Qdrant
// NOT for: fetching data

const data = $input.first().json;
const newPrzetargi = data.newPrzetargi || [];
const qdrantUrl = 'http://qdrant:6333';
const geminiKey = $env.GEMINI_API_KEY || '';

if (newPrzetargi.length === 0) {
  return [{ json: { skip: true } }];
}

// Format WhatsApp message
let msg = '📋 *Nowe przetargi BIP*\n\n';

for (const p of newPrzetargi) {
  msg += '🔹 *' + p.title.substring(0, 200) + '*\n';
  const dd = p.date.slice(8,10) + '.' + p.date.slice(5,7);
  msg += '📅 ' + dd;
  if (p.deadline && p.deadline !== 'None') {
    const dl = p.deadline.length >= 10 ? p.deadline.slice(8,10) + '.' + p.deadline.slice(5,7) : p.deadline;
    msg += ' → termin ' + dl + '\n';
  }
  if (!p.deadline || p.deadline === 'None') msg += '\n';
  msg += '🔗 ' + p.bipLink + '\n\n';
}

// footer removed — clean ending

// Store notified IDs in Qdrant
function simpleHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
  h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
  h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0') + '0000000000000000';
}
function makeUUID(input) {
  const h = simpleHash(input);
  return h.slice(0,8)+'-'+h.slice(8,12)+'-'+h.slice(12,16)+'-'+h.slice(16,20)+'-'+h.slice(20,32);
}

// Store each przetarg as notified
const points = [];
for (const p of newPrzetargi) {
  // Generate a simple embedding (dummy 768-dim zero vector — we only use payload filter, not search)
  const vector = new Array(768).fill(0);
  vector[0] = 0.1; // non-zero to satisfy Qdrant

  points.push({
    id: makeUUID('bip-przetarg-' + p.id),
    vector,
    payload: {
      category: 'bip-przetarg-notified',
      bip_id: p.id,
      title: p.title,
      date: p.date,
      deadline: p.deadline,
      notified_at: new Date().toISOString()
    }
  });
}

if (points.length > 0) {
  await this.helpers.httpRequest({
    method: 'PUT',
    url: qdrantUrl + '/collections/krasnik_news/points',
    body: { points },
    json: true
  }).catch(e => console.log('Store przetargi error:', e.message));
}

return [{ json: { response: msg, chatId: GROUP_JID, count: newPrzetargi.length } }];
